// src/components/InternshipModal.jsx
import React, { useState, useEffect } from "react";
import "./InternshipModal.css";

const InternshipModal = ({ show, onClose, onSave, initialData }) => {
  const [form, setForm] = useState({
    title: "",
    company: "",
    location: "",
    stipend: "",
    duration: "",
    description: "",
  });

  useEffect(() => {
    if (initialData) {
      setForm(initialData);
    } else {
      setForm({
        title: "",
        company: "",
        location: "",
        stipend: "",
        duration: "",
        description: "",
      });
    }
  }, [initialData]);

  const handleChange = (e) => {
    const { name, value } = e.target;
    setForm((prev) => ({ ...prev, [name]: value }));
  };

  const handleSubmit = () => {
    if (!form.title || !form.company || !form.description) {
      alert("Please fill all required fields");
      return;
    }
    onSave(form);
  };

  if (!show) return null;

  return (
    <div className="modal-overlay">
      <div className="modal-box">
        <h2>{initialData ? "Edit Internship" : "Add Internship"}</h2>

        <input
          type="text"
          name="title"
          value={form.title}
          onChange={handleChange}
          placeholder="Title"
          required
        />
        <input
          type="text"
          name="company"
          value={form.company}
          onChange={handleChange}
          placeholder="Company"
          required
        />
        <input
          type="text"
          name="location"
          value={form.location}
          onChange={handleChange}
          placeholder="Location"
        />
        <input
          type="text"
          name="stipend"
          value={form.stipend}
          onChange={handleChange}
          placeholder="Stipend (e.g., 5000)"
        />
        <input
          type="text"
          name="duration"
          value={form.duration}
          onChange={handleChange}
          placeholder="Duration (e.g., 3 months)"
        />
        <textarea
          name="description"
          value={form.description}
          onChange={handleChange}
          placeholder="Description"
          rows="4"
        />

        <div className="modal-buttons">
          <button className="save-btn" onClick={handleSubmit}>
            Save
          </button>
          <button className="cancel-btn" onClick={onClose}>
            Cancel
          </button>
        </div>
      </div>
    </div>
  );
};

export default InternshipModal;
